import React, { useState, useEffect } from "react";
import api from './api';

export default function Profile() {
  const [userProfile, setUserProfile] = useState(null);
  const [userPosts, setUserPosts] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [editName, setEditName] = useState("");
  const [editBio, setEditBio] = useState("");
  const [editAvatar, setEditAvatar] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [commentInput, setCommentInput] = useState({});
  const [expandedComments, setExpandedComments] = useState({});

  // Fetch current user from localStorage and get their posts
  useEffect(() => {
    const loadProfile = async () => {
      try {
        const userData = JSON.parse(localStorage.getItem('user'));
        const token = localStorage.getItem('token');
        
        if (userData && token) {
          try {
            // Lấy thông tin profile từ database
            const profileData = await api.getUserProfile(userData.id);
            const mergedProfile = {
              ...userData,
              display_name: profileData.full_name?.trim() || userData.display_name || userData.username || '',
              bio: profileData.bio || '',
              avatar_url: profileData.avatar_url || userData.avatar_url || ''
            };
            setUserProfile(mergedProfile);
            setEditName(profileData.full_name?.trim() || userData.display_name || userData.username || '');
            setEditBio(profileData.bio || '');
            setEditAvatar(profileData.avatar_url || userData.avatar_url || '');
          } catch (profileErr) {
            console.error('Error fetching profile from DB:', profileErr);
            // Fallback to localStorage
            setUserProfile(userData);
            setEditName(userData.display_name || userData.username || '');
            setEditBio(userData.bio || '');
            setEditAvatar(userData.avatar_url || '');
          }
        }
        
        // Fetch all posts and filter by user
        if (token) {
          try {
            const posts = await api.fetchPosts();
            if (Array.isArray(posts) && userData) {
              const userPostsData = posts.filter(p => p.user_id === userData.id);
              setUserPosts(userPostsData);
            }
          } catch (err) {
            console.error('Error fetching posts:', err);
          }
        }
      } catch (err) {
        console.error('Error loading profile:', err);
        setError('Lỗi tải thông tin profile');
      } finally {
        setLoading(false);
      }
    };
    
    loadProfile();
  }, []);

  const handleSaveProfile = async () => {
    if (editName.trim() === '') {
      setError('Tên không được để trống');
      return;
    }
    
    try {
      const updated = { 
        full_name: editName, 
        bio: editBio,
        avatar_url: editAvatar 
      };

      // Call API to save to database
      const userData = JSON.parse(localStorage.getItem('user'));
      if (userData && userData.id) {
        try {
          const response = await api.updateUserProfile(userData.id, updated);
          if (response && (response.message === 'Updated' || response.message === 'Created')) {
            // Update state từ response
            const updatedProfile = response.data || response;
            const mergedProfile = {
              ...userData,
              display_name: editName,
              bio: editBio,
              avatar_url: editAvatar
            };
            
            // Update localStorage
            localStorage.setItem('user', JSON.stringify(mergedProfile));
            setUserProfile(mergedProfile);
            setIsEditing(false);
            setError('');
          }
        } catch (apiErr) {
          console.error('API Error:', apiErr);
          setError('Lỗi cập nhật profile');
        }
      }
    } catch (err) {
      console.error('Error updating profile:', err);
      setError('Lỗi cập nhật profile');
    }
  };

  const handleAvatarChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditAvatar(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddComment = async (postId) => {
    if (!commentInput[postId]?.trim()) return;
    
    try {
      const response = await api.createComment(postId, commentInput[postId]);
      if (response) {
        setUserPosts(userPosts.map(p => 
          p.id === postId 
            ? { ...p, comments: [...(p.comments || []), response] }
            : p
        ));
        setCommentInput({ ...commentInput, [postId]: '' });
      }
    } catch (err) {
      console.error('Error adding comment:', err);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center bg-[#F4FAFF] min-h-screen pt-[40px] px-6 ml-[72px]">
        <div className="text-center text-gray-500">Đang tải profile...</div>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center bg-[#F4FAFF] min-h-screen pt-[40px] px-6 ml-[72px] pb-8">
      <div className="flex flex-col items-center gap-6 w-full max-w-[1060px]">

        {/* Cover & Profile Header */}
        <div className="bg-white w-full rounded-2xl shadow-lg overflow-hidden">
          {/* Cover Photo */}
          <div className="relative h-64 bg-gradient-to-r from-blue-400 via-blue-300 to-cyan-300">
            <button
              onClick={() => setIsEditing(!isEditing)}
              className="absolute top-4 right-4 bg-white hover:bg-gray-100 text-gray-700 px-4 py-2 rounded-lg shadow-md transition-all font-medium"
            >
              {isEditing ? 'Hủy' : 'Chỉnh sửa profile'}
            </button>
          </div>

          {/* Profile Info */}
          <div className="px-6 pb-6">
            <div className="flex gap-6 items-end mb-4 -mt-20 relative z-10">
              {/* Avatar */}
              <div className="relative group">
                <img
                  src={isEditing ? editAvatar : (userProfile?.avatar_url || "https://via.placeholder.com/150?text=Avatar")}
                  alt="avatar"
                  className="w-40 h-40 rounded-full border-4 border-white shadow-lg object-cover"
                />
                {isEditing && (
                  <label className="absolute inset-0 flex items-center justify-center rounded-full bg-black/50 opacity-0 group-hover:opacity-100 cursor-pointer transition-opacity">
                    <span className="text-white text-sm font-medium">Thay đổi</span>
                    <input
                      type="file"
                      accept="image/*"
                      onChange={handleAvatarChange}
                      className="hidden"
                    />
                  </label>
                )}
              </div>
              
              {/* User Info */}
              <div className="flex-1 mb-2">
                {isEditing ? (
                  <div className="flex flex-col gap-3">
                    <input
                      type="text"
                      value={editName}
                      onChange={(e) => setEditName(e.target.value)}
                      placeholder="Tên của bạn"
                      className="text-2xl font-bold bg-gray-100 text-black px-3 py-2 rounded-lg border-2 border-blue-300 focus:outline-none focus:border-blue-500"
                    />
                    <textarea
                      value={editBio}
                      onChange={(e) => setEditBio(e.target.value)}
                      placeholder="Thêm bio của bạn..."
                      className="text-gray-600 bg-gray-50 px-3 py-2 rounded-lg border border-gray-300 resize-none focus:outline-none focus:border-blue-400 text-sm"
                      rows="2"
                      maxLength="200"
                    />
                    <div className="flex gap-2">
                      <button
                        onClick={handleSaveProfile}
                        className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg transition-all font-medium"
                      >
                        Lưu thay đổi
                      </button>
                      <button
                        onClick={() => {
                          setIsEditing(false);
                          setEditName(userProfile?.display_name || userProfile?.username || '');
                          setEditBio(userProfile?.bio || '');
                          setEditAvatar(userProfile?.avatar_url || '');
                          setError('');
                        }}
                        className="bg-gray-400 hover:bg-gray-500 text-white px-4 py-2 rounded-lg transition-all font-medium"
                      >
                        Hủy
                      </button>
                    </div>
                  </div>
                ) : (
                  <div>
                    <h1 className="text-3xl font-bold text-black mb-2">
                      {userProfile?.display_name || userProfile?.username || 'User'}
                    </h1>
                    <p className="text-gray-600 mb-3">
                      {userProfile?.bio || 'Chưa có bio'}
                    </p>
                  </div>
                )}
              </div>
            </div>

            {error && <div className="text-red-500 text-sm bg-red-50 p-2 rounded mt-2">{error}</div>}
          </div>
        </div>

        {/* User Stats */}
        <div className="grid grid-cols-3 gap-4 w-full">
          <div className="bg-white p-4 rounded-xl shadow-md text-center">
            <p className="text-2xl font-bold text-blue-600">{userPosts.length}</p>
            <p className="text-gray-600 text-sm">Bài đăng</p>
          </div>
          <div className="bg-white p-4 rounded-xl shadow-md text-center">
            <p className="text-2xl font-bold text-blue-600">0</p>
            <p className="text-gray-600 text-sm">Bạn bè</p>
          </div>
          <div className="bg-white p-4 rounded-xl shadow-md text-center">
            <p className="text-2xl font-bold text-blue-600">0</p>
            <p className="text-gray-600 text-sm">Theo dõi</p>
          </div>
        </div>

        {/* --- Thông tin chi tiết (3 ô hàng đầu + 3 select hàng 2) --- */}
        <div className="bg-white w-full p-6 rounded-2xl shadow-lg">
          {/* Hàng đầu */}
          <div className="flex justify-center gap-6 mb-4">
            <div className="flex flex-col items-center bg-[#FFDEF8] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Học vấn</span>
            </div>
            <div className="flex flex-col items-center bg-[#FFE9FA] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Những điều về tui</span>
            </div>
            <div className="flex flex-col items-center bg-[#C6E1FF] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">#hashtag</span>
            </div>
          </div>

          {/* Hàng thứ hai có danh sách chọn */}
          <div className="flex justify-center gap-6">
            {/* Khoa */}
            <div className="flex flex-col items-center bg-[#C6E1FF] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Khoa</span>
              <select className="w-[160px] bg-white text-gray-700 text-sm rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-blue-300">
                <option value="CNTT">Công nghệ thông tin</option>
                <option value="QTKD">Quản trị kinh doanh</option>
                <option value="NNA">Ngôn ngữ Anh</option>
              </select>
            </div>

            {/* Nơi ở */}
            <div className="flex flex-col items-center bg-[#FFDEF8] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Nơi ở</span>
              <select className="w-[160px] bg-white text-gray-700 text-sm rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-pink-300">
                <option value="HCM">TP. Hồ Chí Minh</option>
                <option value="HN">Hà Nội</option>
                <option value="DN">Đà Nẵng</option>
              </select>
            </div>

            {/* Quê quán */}
            <div className="flex flex-col items-center bg-[#FFE9FA] w-[200px] py-3 rounded-xl shadow">
              <span className="text-black font-semibold mb-1">Quê quán</span>
              <select className="w-[160px] bg-white text-gray-700 text-sm rounded-md px-2 py-1 focus:outline-none focus:ring-2 focus:ring-purple-300">
                <option value="HCM">TP. Hồ Chí Minh</option>
                <option value="HN">Hà Nội</option>
                <option value="DN">Đà Nẵng</option>
              </select>
            </div>
          </div>
        </div>

        {/* --- Danh sách bài viết của user --- */}
        <div className="w-full">
          <h2 className="text-xl font-bold text-gray-800 mb-4">Bài đăng của tôi</h2>
          
          {userPosts.length === 0 ? (
            <div className="bg-white w-full p-6 rounded-2xl shadow-lg text-center text-gray-500">
              Chưa có bài đăng nào
            </div>
          ) : (
            userPosts.map((post) => {
              const postMediaArray = post.post_media || post.postMedia || [];
              const images = postMediaArray
                .map(pm => pm.media?.url || pm.media?.public_id)
                .filter(Boolean);

              return (
                <div key={post.id} className="bg-white w-full p-5 rounded-2xl shadow-md mb-4">
                  {/* Post Header */}
                  <div className="flex items-center gap-3 mb-4 pb-3 border-b border-gray-200">
                    <img
                      src={post.user?.avatar_url || "https://via.placeholder.com/50?text=Avatar"}
                      alt="avatar"
                      className="w-[50px] h-[50px] rounded-full object-cover"
                    />
                    <div>
                      <p className="font-semibold text-black">
                        {post.user?.display_name || post.user?.username || 'User'}
                      </p>
                      <p className="text-xs text-gray-500">
                        {new Date(post.created_at).toLocaleString('vi-VN')}
                      </p>
                    </div>
                  </div>

                  {/* Post Content */}
                  <p className="text-black mb-3">{post.content}</p>

                  {/* Post Images */}
                  {images.length > 0 && (
                    <div className={`grid gap-2 mb-4 ${images.length === 1 ? 'grid-cols-1' : 'grid-cols-2'}`}>
                      {images.map((img, idx) => (
                        <img
                          key={idx}
                          src={img}
                          alt="post"
                          className="w-full h-64 object-cover rounded-lg"
                          onError={(e) => {
                            e.target.src = "https://via.placeholder.com/400?text=Image+Error";
                          }}
                        />
                      ))}
                    </div>
                  )}

                  {/* Comments Section */}
                  <div className="border-t border-gray-200 pt-3">
                    <div className="text-sm text-gray-500 mb-3">
                      {post.comments?.length || 0} bình luận
                    </div>

                    {/* Comments List */}
                    {expandedComments[post.id] && post.comments?.length > 0 && (
                      <div className="mb-3 bg-gray-50 p-3 rounded-lg max-h-64 overflow-y-auto space-y-2">
                        {post.comments.map((comment) => (
                          <div key={comment.id} className="text-sm">
                            <span className="font-semibold text-black">
                              {comment.user?.display_name || comment.user?.username || 'User'}
                            </span>
                            <p className="text-gray-700 text-xs">{comment.content}</p>
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Toggle Comments */}
                    {post.comments?.length > 0 && (
                      <button
                        onClick={() => setExpandedComments({
                          ...expandedComments,
                          [post.id]: !expandedComments[post.id]
                        })}
                        className="text-blue-500 text-sm hover:underline mb-2"
                      >
                        {expandedComments[post.id] ? 'Ẩn bình luận' : 'Xem bình luận'}
                      </button>
                    )}

                    {/* Add Comment */}
                    <div className="flex gap-2">
                      <input
                        type="text"
                        value={commentInput[post.id] || ''}
                        onChange={(e) => setCommentInput({ ...commentInput, [post.id]: e.target.value })}
                        onKeyPress={(e) => e.key === 'Enter' && handleAddComment(post.id)}
                        placeholder="Viết bình luận..."
                        className="flex-1 px-3 py-2 border border-gray-300 rounded-lg text-sm text-black focus:outline-none focus:border-blue-400"
                      />
                      <button
                        onClick={() => handleAddComment(post.id)}
                        className="bg-blue-500 hover:bg-blue-600 text-white px-4 py-2 rounded-lg text-sm transition-all"
                      >
                        Gửi
                      </button>
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>
    </div>
  );
}
